namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple and delicious traditional Italian pizza.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F (245°C).", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."]
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy Roman pasta made with eggs, cheese, and pancetta.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
                Steps = ["Cook spaghetti in salted boiling water.", "Fry pancetta until crispy.", "Whisk eggs with grated Pecorino and pepper.", "Toss hot pasta with pancetta off heat.", "Add egg mixture and toss quickly to coat.", "Serve immediately with extra cheese."]
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer 15 minutes.", "Stir in cream and cooked chicken.", "Simmer 10 minutes and serve with rice."]
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
                Description = "A vibrant stir-fried noodle dish packed with vegetables.",
                Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Eggs", "Green onions"],
                Steps = ["Soak rice noodles in warm water 20 minutes.", "Press and cube tofu, then pan-fry until golden.", "Scramble eggs in the same pan.", "Add noodles, tamarind paste, and fish sauce.", "Toss with bean sprouts and green onions.", "Serve with crushed peanuts and lime wedges."]
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Classic seasoned beef tacos with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry pan.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese, and sour cream.", "Serve with salsa on the side."]
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh and creamy avocado dip.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Salt", "Tomato"],
                Steps = ["Halve and pit avocados, scoop into bowl.", "Mash to desired consistency.", "Mix in lime juice, diced onion, and jalapeño.", "Fold in chopped cilantro and diced tomato.", "Season with salt to taste.", "Serve immediately with tortilla chips."]
            },
            new Recipe
            {
                Id = 7, Title = "Green Curry", Category = "Thai",
                Description = "A fragrant coconut milk curry with vegetables and Thai basil.",
                Ingredients = ["Green curry paste", "Coconut milk", "Chicken or tofu", "Bamboo shoots", "Thai basil", "Fish sauce", "Sugar", "Bell pepper"],
                Steps = ["Heat coconut cream in a wok until oil separates.", "Fry curry paste for 2 minutes.", "Add protein and cook through.", "Pour in coconut milk and bring to a simmer.", "Add vegetables and season with fish sauce and sugar.", "Stir in Thai basil and serve over jasmine rice."]
            },
            new Recipe
            {
                Id = 8, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Description = "Chewy, golden-brown cookies loaded with chocolate chips.",
                Ingredients = ["Butter", "Sugar", "Brown sugar", "Eggs", "Vanilla", "Flour", "Baking soda", "Salt", "Chocolate chips"],
                Steps = ["Preheat oven to 375°F (190°C).", "Cream butter with both sugars until fluffy.", "Beat in eggs and vanilla.", "Mix flour, baking soda, and salt, then combine with wet ingredients.", "Fold in chocolate chips.", "Drop spoonfuls onto baking sheet and bake 9-11 minutes."]
            },
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().Order().ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(string title, string category, string description, List<string> ingredients, List<string> steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Description = description,
            Ingredients = ingredients,
            Steps = steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

