arguments.file_text:
@page "/"
@inject RecipeService RecipeService

<PageTitle>RecipeShare — Home</PageTitle>

<div class="text-center mb-4">
    <h1>🍽️ RecipeShare</h1>
    <p class="lead">Discover and share delicious recipes from around the world.</p>
</div>

<h2>Browse by Category</h2>
<div class="row">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-3 mb-3">
            <div class="card h-100 shadow-sm">
                <div class="card-body text-center">
                    <h4 class="card-title">@CategoryIcon(category) @category</h4>
                    <p class="text-muted">@RecipeService.GetByCategory(category).Count recipe(s)</p>
                    <a href="/categories/@Uri.EscapeDataString(category)" class="btn btn-outline-primary">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string CategoryIcon(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Thai" => "🇹🇭",
        "Mexican" => "🇲🇽",
        "Desserts" => "🍰",
        _ => "🍴"
    };
}

@page "/categories/{CategoryName}"
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        @if (recipe.TotalRatings > 0)
                        {
                            <small class="text-muted">⭐ @recipe.AverageRating.ToString("F1") (@recipe.TotalRatings ratings)</small>
                        }
                    </div>
                    <div class="card-footer">
                        <a href="/recipes/@recipe.Id" class="btn btn-sm btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-link mt-3">← Back to categories</a>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> recipes = [];

    protected override void OnInitialized()
    {
        recipes = RecipeService.GetByCategory(Uri.UnescapeDataString(CategoryName));
    }
}

@page "/recipes/{Id:int}"
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: <a href="/categories/@Uri.EscapeDataString(recipe.Category)">@recipe.Category</a></p>
    <p>@recipe.Description</p>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <h4>Steps</h4>
            <ol>
                @foreach (var step in recipe.Steps)
                {
                    <li class="mb-2">@step</li>
                }
            </ol>
        </div>
    </div>

    <div class="card mt-3 mb-3" style="max-width: 320px;">
        <div class="card-body">
            <h5 class="card-title">Rate this recipe</h5>
            <StarRating RecipeId="recipe.Id" />
        </div>
    </div>

    <a href="/categories/@Uri.EscapeDataString(recipe.Category)" class="btn btn-link">← Back to @recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeService RecipeService

@if (submitted)
