toolArgs.file_text:
@page "/recipes/{Id:int}"
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: <a href="/categories/@Uri.EscapeDataString(recipe.Category)">@recipe.Category</a></p>
    <p>@recipe.Description</p>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <h4>Steps</h4>
            <ol>
                @foreach (var step in recipe.Steps)
                {
                    <li class="mb-2">@step</li>
                }
            </ol>
        </div>
    </div>

    <div class="card mt-3 mb-3" style="max-width: 320px;">
        <div class="card-body">
            <h5 class="card-title">Rate this recipe</h5>
            <StarRating RecipeId="recipe.Id" />
        </div>
    </div>

    <a href="/categories/@Uri.EscapeDataString(recipe.Category)" class="btn btn-link">← Back to @recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeService RecipeService

@if (submitted)
{
    <div class="text-success mb-2">✅ You rated this @selectedRating/5 stars! Thanks!</div>
}

<div>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              style="font-size: 1.5rem; cursor: pointer; color: @(star <= displayRating ? "#ffc107" : "#ddd");"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => displayRating = star"
              @onmouseout="() => displayRating = selectedRating"
              title="@star star(s)">★</span>
    }
</div>

@code {
    [Parameter, EditorRequired] public int RecipeId { get; set; }

    private int selectedRating;
    private int displayRating;
    private bool submitted;

    private void SubmitRating(int stars)
    {
        selectedRating = stars;
        displayRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        submitted = true;
    }
}

